import uasyncio as asyncio
from microcoapy import CoAPServer, RequestType

class IoTDevice:
    def __init__(self):
        self.sensors = {'temp': 25.0}
        self.actuators = {'light': False}

    async def handle_request(self, request):
        path = request.uri_path
        if path == '/sensors/temp':
            if request.method == RequestType.GET:
                response = CoAPResponse()
                response.payload = str(self.sensors['temp']).encode('utf-8')
                return response
            elif request.method == RequestType.PUT:
                try:
                    new_temp = float(request.payload.decode('utf-8'))
                    self.sensors['temp'] = new_temp
                    response = CoAPResponse()
                    response.code = 2.04  # Changed
                    return response
                except ValueError:
                    response = CoAPResponse()
                    response.code = 4.00  # Bad Request
                    return response
        elif path == '/actuators/light':
            if request.method == RequestType.GET:
                response = CoAPResponse()
                response.payload = str(self.actuators['light']).encode('utf-8')
                return response
            elif request.method == RequestType.PUT:
                try:
                    new_state = bool(int(request.payload.decode('utf-8')))
                    self.actuators['light'] = new_state
                    response = CoAPResponse()
                    response.code = 2.04  # Changed
                    return response
                except ValueError:
                    response = CoAPResponse()
                    response.code = 4.00  # Bad Request
                    return response

        response = CoAPResponse()
        response.code = 4.05  # Method Not Allowed
        return response

async def main():
    device = IoTDevice()
    server = CoAPServer(device.handle_request)
    await server.start(5683)  # CoAP default port
    print("CoAP Server started on port 5683")
    while True:
        await asyncio.sleep(1)

if __name__ == "__main__":
    asyncio.run(main())